 93→    private void autoSelectNewestFiles() {
 94→        // 自动选择Download/Weixin目录中最新的一对文件（音频+文档）
 95→        new Thread(() -> {
 96→            try {
 97→                File downloadDir = new File(Environment.getExternalStorageDirectory(), "Download");
 98→                File weixinDir = new File(downloadDir, "Weixin");
 99→                File targetDir = weixinDir.exists() ? weixinDir : downloadDir;
100→
101→                File[] files = targetDir.listFiles();
102→                if (files == null || files.length == 0) return;
103→
104→                // 按修改时间排序，最新的在前
105→                java.util.Arrays.sort(files, (a, b) -> Long.compare(b.lastModified(), a.lastModified()));
106→
107→                File newestAudio = null;
108→                File newestDoc = null;
109→
110→                // 找最新的音频和文档
111→                for (File f : files) {
112→                    String name = f.getName().toLowerCase();
113→                    if (newestAudio == null && isAudioFile(name)) {
114→                        newestAudio = f;
115→                    } else if (newestDoc == null && isDocFile(name)) {
116→                        newestDoc = f;
117→                    }
118→                    if (newestAudio != null && newestDoc != null) break;
119→                }
120→
121→                // 自动填充
122→                if (newestAudio != null) {
123→                    String path = newestAudio.getAbsolutePath();
124→                    audioPath = path;
125→                    final String name = newestAudio.getName();
126→                    runOnUiThread(() -> tvAudioName.setText(name));
127→                    Log.i(TAG, "自动选择音频: " + name);
128→                }
129→                if (newestDoc != null) {
130→                    String path = newestDoc.getAbsolutePath();
131→                    docPath = path;
132→                    final String name = newestDoc.getName();
133→                    runOnUiThread(() -> tvDocName.setText(name));
134→                    Log.i(TAG, "自动选择文档: " + name);
135→                }
136→            } catch (Exception e) {
137→                Log.e(TAG, "自动选择文件失败", e);
138→            }
139→        }).start();
140→    }
